/// Fold symmetric nested selects where the two inner selects have the same
/// condition but swapped true/false values.
/// Pattern:
///   %sel1 = select i1 %c1, T %a, T %b
///   %sel2 = select i1 %c1, T %b, T %a
///   %ret = select i1 %c2, T %sel1, T %sel2
/// Transforms to:
///   %xor = xor i1 %c1, %c2
///   %ret = select i1 %xor, T %b, T %a
static Instruction *foldSymmetricSelects(SelectInst &SI,
                                         InstCombiner::BuilderTy &Builder) {
  Value *Cond = SI.getCondition();
  Value *TrueVal = SI.getTrueValue();
  Value *FalseVal = SI.getFalseValue();

  // Both operands must be selects.
  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
  if (!TrueSI || !FalseSI)
    return nullptr;

  // Inner selects must have the same condition.
  Value *InnerCond = TrueSI->getCondition();
  if (InnerCond != FalseSI->getCondition())
    return nullptr;

  // Check if the true/false values are swapped (symmetric pattern).
  // Pattern 1: sel1 = c1 ? a : b, sel2 = c1 ? b : a
  if (TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
      TrueSI->getFalseValue() == FalseSI->getTrueValue()) {
    Value *A = TrueSI->getTrueValue();
    Value *B = TrueSI->getFalseValue();
    // ret = c2 ? (c1 ? a : b) : (c1 ? b : a)
    //     = (c2 && c1) ? a : (c2 && !c1) ? b : (!c2 && c1) ? b : a
    //     = (c1 == c2) ? a : b
    //     = (c1 XOR c2) ? b : a
    Value *XorCond = Builder.CreateXor(InnerCond, Cond);
    return SelectInst::Create(XorCond, B, A);
  }

  // Pattern 2: sel1 = c1 ? b : a, sel2 = c1 ? a : b (swapped from pattern 1)
  // This is equivalent to just swapping the outer select's true/false
  if (TrueSI->getTrueValue() == FalseSI->getTrueValue() &&
      TrueSI->getFalseValue() == FalseSI->getFalseValue()) {
    // Both inner selects have the same values, not symmetric
    return nullptr;
  }

  return nullptr;
}

